\section*{Resolução Técnica}

\textbf{Resposta correta:} E (convecção).

\textbf{Estratégia:} Identificar o modo de transferência de calor entre o coletor solar e o reservatório com base nos princípios físicos e no funcionamento do equipamento.

\textbf{Passos:}
\begin{enumerate}
  \item Compreender que o coletor solar aquece a água usando radiação solar.
  \item Determinar que a água quente se movimenta do coletor para o reservatório, indicando transporte pelo fluido.
  \item Reconhecer que condução ocorre em sólidos, radiação envolve ondas eletromagnéticas e absorção refere-se a captação de energia, não transferência entre partes.
  \item Concluir que o calor é transferido do coletor ao reservatório pelo movimento da água quente, caracterizando convecção.
\end{enumerate}

\textbf{Uso de fórmulas:} Nenhuma fórmula específica foi necessária para a resolução.

\textbf{Evidência visual:} O esquema mostra circulação de água fria para o coletor e saída de água quente para o reservatório, evidenciando transporte por fluido.

\textbf{Confiança na resposta:} Alta.

payload.didacticExplanation:
\section*{Explicação Didática}

\textbf{Breve explicação:} O aquecedor solar transfere calor do coletor para o reservatório principalmente por convecção, que é o movimento da água quente transportando energia térmica.

\textbf{Passo a passo didático:}
\begin{enumerate}
  \item A água fria entra no coletor, onde é aquecida pela radiação solar.
  \item Conhecer os modos de transferência de calor: condução, convecção, radiação, difusão e absorção.
  \item A água quente sai do coletor e circula até o reservatório por movimento do fluido.
  \item Esse movimento é convecção, responsável por transportar o calor entre coletor e reservatório.
  \item Assim, a transferência não é condução nem radiação, mas convecção devido à circulação do fluido.
\end{enumerate}

\textbf{Erros comuns a evitar:}
\begin{itemize}
  \item Confundir difusão com transferência de calor.
  \item Associar absorção como transferência de calor entre coletor e reservatório.
  \item Pensar que condução domina a transferência porque há contato físico.
  \item Confundir radiação solar com a transferência interna de calor.
\end{itemize}

\textbf{Dicas para ensino:}
\begin{itemize}
  \item Utilizar exemplos cotidianos de convecção, como a água que circula numa panela ao ferver.
  \item Explicar claramente as diferenças entre condução, convecção e radiação.
  \item Analisar esquemas técnicos para identificar o fluxo do fluido e os modos de transferência de calor.
  \item Ressaltar que absorção é a captação inicial de energia, não a transferência interna entre componentes.
\end{itemize}

payload.commonPitfalls:
\section*{Armadilhas e Dificuldades}

\begin{itemize}
  \item \textbf{Difusão (Opção A):} Pode ser confundida com transferência de calor pelo movimento de partículas, porém não é o mecanismo principal para a transferência térmica aqui.
  \item \textbf{Absorção (Opção B):} Relacionada à captação da radiação solar pelo coletor, não à transferência do calor para o reservatório.
  \item \textbf{Condução (Opção C):} Apesar de haver contato físico, a condução ocorre principalmente em sólidos; neste caso o calor se transfere pelo fluido em movimento, caracterizando convecção.
  \item \textbf{Radiação (Opção D):} É o modo pelo qual o coletor recebe energia do sol, não o mecanismo interno entre coletor e reservatório.
\end{itemize}

